    eventType: EventType
    eventDescription: EventDescription
    eventDate: Instant
}

service TrialService {
    operation createTrial(trial: Trial): Trial
    operation enrolPatient(enrolment: Enrolment): Enrolment
    operation recordEvent(event: TrialEvent): TrialEvent
    find { TrialEvent[] }
}

namespace billing {

    type SubscriberId inherits String

    model Subscriber {
        subscriberId: SubscriberId
    }

    enum BillingCadence {
        MONTHLY,
        QUARTERLY,
        ANNUAL
    }

    type PlanId inherits String

    closed model Plan {
        planId: PlanId
        name: String
        @Sensitive
        price: Decimal
        billingCadence: BillingCadence
    }

    type SubscriptionId inherits String

    closed model Subscription {
        subscriptionId: SubscriptionId
        subscriber: Subscriber
        plan: Plan
        startedAt: Instant
        renewedAt: Instant?
    }

    type InvoiceId inherits String

    closed model Invoice {
        invoiceId: InvoiceId
        subscription: Subscription
        @Sensitive
        amount: Decimal
        dueAt: Instant
    }

    service BillingService {
        operation subscribe(subscriber: Subscriber, plan: Plan): Subscription
        operation cancelSubscription(subscriptionId: SubscriptionId)
        operation generateInvoice(subscriptionId: SubscriptionId): Invoice
    }
}
